const sgMail = require('@sendgrid/mail');
sgMail.setApiKey(
  'Your API Key' 
);
addEventListener('fetch', event => {
    const url = new URL(`${event.request.url}`);

    if (url.pathname == '/email-api') {
        return event.respondWith(emailRequest(event));
    } else if (url.pathname == '/payment-api') {
        return event.respondWith(paymentRequest(event));
    }
});


async function emailRequest(event) {
    const request = await fetch('https://<YourDomain>.com/api/email', {
        headers: new Headers({
            'Content-Type': 'application/json'
        }),
    });
    return event.waitUntil(new Response(`
<html>
  <head><title>Email API</title></head>
  <body>
    Email API has been accessed.
  </body>
</html>`, request));
}

 async function paymentRequest(event) {

    const request = await fetch('https://<YourDomain>.com/api/payment',  {
        method: 'POST', 
        headers:{
            'Content-Type': 'application/json'
        }
    });
  
    return event.waitUntil(new Response(`
<html>
  <head><title>Payment API</title></head>
  <body>
     Payment API has been accessed.
  </body>
</html>`, request));

 };